// 用户"待回复"轮次 ID（按联系人），连发多条共用同一 roundId，AI 回复后清掉
let _pendingMeRoundId = {};
// 手机聊天会话基准时间——任意联系人收到 AI 回复后更新，跨联系人共享
let _chatSessionBaseTime = '';
// phoneDown：线上聊天触发收手机后的 pending 数据，供 chat.js 消费
let _pendingPhoneDown = null;
// 语音模式状态：{ contactId: true/false }
let _chatVoiceMode = {};
// 结构：{ contactId: { name: '联系人名', msgs: [{role, text, time}] } }
let _chatRoundLog = {};

function _persistChatRoundLog() {
  try {
    const convId = Conversations.getCurrent && Conversations.getCurrent();
    if (!convId) return;
    const conv = Conversations.getList().find(c => c.id === convId);
    if (!conv) return;
    conv.phoneData = conv.phoneData || {};
    conv.phoneData.pendingChatRoundLog = Object.keys(_chatRoundLog).length > 0 ? JSON.parse(JSON.stringify(_chatRoundLog)) : null;
    Conversations.saveList && Conversations.saveList();
  } catch(_) {}
}

function reloadChatRoundLog() {
  try {
    const convId = Conversations.getCurrent && Conversations.getCurrent();
    if (!convId) { _chatRoundLog = {}; return; }
    const conv = Conversations.getList().find(c => c.id === convId);
    _chatRoundLog = (conv?.phoneData?.pendingChatRoundLog && typeof conv.phoneData.pendingChatRoundLog === 'object')
      ? JSON.parse(JSON.stringify(conv.phoneData.pendingChatRoundLog))
      : {};
  } catch(_) { _chatRoundLog = {}; }
}

function _addChatMessageToRoundLog(contactId, role, text, time, contactName, opts) {
  if (!contactId || !text) return;
  opts = opts || {};
  if (!_chatRoundLog[contactId]) {
    _chatRoundLog[contactId] = { name: contactName || contactId, msgs: [], isGroup: !!opts.isGroup };
  }
  if (opts.isGroup) _chatRoundLog[contactId].isGroup = true;
  _chatRoundLog[contactId].msgs.push({ role, text, time: (time || '').trim(), senderName: opts.senderName || '' });
  _persistChatRoundLog();
}

function _formatChatRoundLog() {
  if (Object.keys(_chatRoundLog).length === 0) return [];
  const lines = [];
  for (const contactId in _chatRoundLog) {
    const entry = _chatRoundLog[contactId];
    if (!entry || !entry.msgs || !entry.msgs.length) continue;
    const contactName = entry.name || contactId;
    if (entry.isGroup) {
      lines.push(`在手机聊天APP的群聊「${contactName}」里新增以下群消息（仅供了解上下文，不要在线下剧情中以对话格式复述这些内容）：`);
      for (const m of entry.msgs) {
        const timeStr = m.time ? `[${m.time}] ` : '';
        if (m.role === 'system') { lines.push(`  [系统] ${timeStr}${m.text}`); continue; }
        const who = m.role === 'me' ? '{{user}}' : (m.senderName || '群成员');
        lines.push(`  ${who} ${timeStr}：${m.text}`);
      }
    } else {
      lines.push(`在手机聊天APP与「${contactName}」新增以下对话（仅供了解上下文，不要在线下剧情中以对话格式复述这些内容）：`);
      for (const m of entry.msgs) {
        const who = m.role === 'me' ? '{{user}}' : contactName;
        const timeStr = m.time ? `[${m.time}] ` : '';
        lines.push(`  ${who} ${timeStr}：${m.text}`);
      }
    }
  }
  return lines;
}

function _flushChatRoundLog() {
  const chatLines = _formatChatRoundLog();
  if (chatLines.length > 0) {
    // 聊天日志作为一条完整 log 加入 action log
    _actionLog.push(chatLines.join('\n'));
    _actionLogForBackstage.push(chatLines.join('\n'));
  }
  _chatRoundLog = {};
  _persistChatRoundLog();
}

  // ===== 辅助 =====
  function _isAnyWorldview() {
    const wv = document.body.getAttribute('data-worldview');
    return !!wv && wv !== '';
  }

  // ===== 数据层 =====
  // phoneData 存在 conversation 对象上，按对话隔离
  // 深度比较两个值是否相等（用于判断 phoneData 是否还是初始默认态）
  function _phoneDeepEqual(a, b) {
    if (a === b) return true;
    if (a === null || b === null || a === undefined || b === undefined) return a === b;
    if (typeof a !== 'object' || typeof b !== 'object') return false;
    const ka = Object.keys(a), kb = Object.keys(b);
    if (ka.length !== kb.length) return false;
    for (const k of ka) {
      if (!Object.prototype.hasOwnProperty.call(b, k)) return false;
      if (!_phoneDeepEqual(a[k], b[k])) return false;
    }
    return true;
  }
  // 判断 phoneData 是否仍是"初始空白态"（与默认结构完全一致）。
  // 用深比较而非逐字段白名单——这样新增任何 App 字段都自动纳入，永远不会漏：
  //   只要用户在任意 App 里产生过数据（哪怕只是改了壁纸/设置），就不算空白态。
  // 一旦判定"非空白"：① 该数据值得备份；② 不能被旧备份当成空白态覆盖（防丢核心）。
  function _phoneDataIsPristine(pd) {
    if (!pd || typeof pd !== 'object') return true;
    const def = _defaultPhoneData();
    for (const k in def) {
      if (!_phoneDeepEqual(pd[k], def[k])) return false;
    }
    return true;
  }
  async function _getPhoneData() {
    const convId = Conversations.getCurrent();
    if (!convId) return null;
    const conv = Conversations.getList().find(c => c.id === convId);
    if (!conv) return null;
    if (!conv.phoneData) {
      conv.phoneData = _defaultPhoneData();
      // 不 await——避免 saveList hang 住阻塞调用方
      Conversations.saveList().catch(() => {});
    } else {
      // 兼容旧 phoneData：补齐 _defaultPhoneData 里有但旧数据没有的字段
      // 防止旧版本对话升级后字段缺失导致 .push/.unshift 报错
      const defaults = _defaultPhoneData();
      let patched = false;
      for (const k in defaults) {
        if (conv.phoneData[k] === undefined) {
          conv.phoneData[k] = defaults[k];
          patched = true;
        }
      }
      if (patched) Conversations.saveList().catch(() => {});
      // 一次性迁移：从 videoDiscover 倒灌进 videoWorks + 补 watched 标记
      const vw = conv.phoneData.videoWorks;
      if (!Array.isArray(vw)) conv.phoneData.videoWorks = [];
      const byId = {};
      conv.phoneData.videoWorks.forEach(w => { if (w && w.id) byId[w.id] = w; });
      let migrated = false;
      const disc = conv.phoneData.videoDiscover;
      if (disc && typeof disc === 'object' && !Array.isArray(disc)) {
        Object.values(disc).forEach(list => {
          if (!Array.isArray(list)) return;
          list.forEach(w => {
            if (!w || !w.id || byId[w.id]) return;
            conv.phoneData.videoWorks.push(w);
            byId[w.id] = w;
            migrated = true;
          });
        });
      }
      conv.phoneData.videoWorks.forEach(w => {
        if (w && !w.watched && (w.script || w.blueprint)) {
          w.watched = true;
          w.watchedAt = w.watchedAt || 0;
          migrated = true;
        }
      });
      if (migrated) Conversations.saveList().catch(() => {});
    }
    // phoneData 防丢：如果当前数据仍是初始空白态、但备份里有用户数据，自动恢复
    try {
      const isEmptyState = _phoneDataIsPristine(conv.phoneData);
      if (isEmptyState && convId) {
        const backup = await DB.get('gameState', `phoneBackup_${convId}`);
        if (backup && backup.value && typeof backup.value === 'object') {
          const bk = backup.value;
          if (!_phoneDataIsPristine(bk)) {
            // 备份里有实质内容，恢复
            conv.phoneData = bk;
            Conversations.saveList().catch(() => {});
            console.warn('[Phone] phoneData 疑似被重置，已从备份恢复');
          }
        }
      }
    } catch(_) {}
    return conv.phoneData;
  }

  // 同步读取（不补字段，仅用于渲染读数据）
  function _getPhoneDataSync() {
    const convId = Conversations.getCurrent();
    if (!convId) return null;
    const conv = Conversations.getList().find(c => c.id === convId);
    if (!conv || !conv.phoneData) return null;
    return conv.phoneData;
  }

  async function _savePhoneData() {
    try { await Conversations.saveList(); } catch(_) {}
    // phoneData 整体备份：防止 conversations 数据回退/重置导致全部丢失
    try {
      const convId = Conversations.getCurrent();
      const conv = convId && Conversations.getList().find(c => c.id === convId);
      const pd = conv?.phoneData;
      if (convId && pd && !_phoneDataIsPristine(pd)) {
        await DB.put('gameState', { key: `phoneBackup_${convId}`, value: pd });
      }
    } catch(_) {}
  }

