  function _renderBattery(level, charging) {
 const el = document.getElementById('phone-battery');
 if (!el) return;
 if (typeof level !== 'number' || !Number.isFinite(level)) {
 el.innerHTML = '<span class="phone-battery-text">--%</span><span class="phone-battery-shell"><span class="phone-battery-fill" style="width:45%"></span></span>';
 return;
 }
 const pct = Math.max(0, Math.min(100, Math.round(level *100)));
 el.classList.toggle('charging', !!charging);
 el.innerHTML = `<span class="phone-battery-text">${pct}%${charging ? ' ⚡' : ''}</span><span class="phone-battery-shell"><span class="phone-battery-fill" style="width:${pct}%"></span></span>`;
}
async function _refreshBattery() {
 try {
 if (navigator.getBattery) {
 const battery = await navigator.getBattery();
 _batteryRef = battery;
 _renderBattery(battery.level, battery.charging);
 if (!battery._phoneBound) {
 battery.addEventListener('levelchange', () => _renderBattery(battery.level, battery.charging));
 battery.addEventListener('chargingchange', () => _renderBattery(battery.level, battery.charging));
 battery._phoneBound = true;
 }
 } else {
 _renderBattery(null, false);
 }
 } catch(_) {
 _renderBattery(null, false);
 }
}
function _startBatteryTicker() {
 _refreshBattery();
 clearInterval(_batteryTimer);
 _batteryTimer = setInterval(_refreshBattery,60000);
}
function _stopBatteryTicker() {
 clearInterval(_batteryTimer);
 _batteryTimer = null;
}

// ===== 手机主题（全局，存 localStorage）=====
// 'glass'（默认·玻璃冰糖）| 'fudge'（奶油软糖·实色圆润）
const PHONE_THEMES = ['glass', 'fudge'];
const _PHONE_THEME_KEY = 'tianshu_phone_theme';
function _getPhoneTheme() {
  try {
    const t = localStorage.getItem(_PHONE_THEME_KEY);
    return PHONE_THEMES.includes(t) ? t : 'glass';
  } catch (_) { return 'glass'; }
}
function _setPhoneTheme(theme) {
  const t = PHONE_THEMES.includes(theme) ? theme : 'glass';
  try { localStorage.setItem(_PHONE_THEME_KEY, t); } catch (_) {}
  const shell = document.querySelector('#phone-modal .phone-shell');
  if (shell) _applyPhoneTheme(shell);
}
function _applyPhoneTheme(shell) {
    if (!shell) return;
    const t = _getPhoneTheme();
    PHONE_THEMES.forEach(name => shell.classList.toggle('phone-theme-' + name, name === t));
  }

  // ===== 奶油软糖主题：兑换码解锁（全局，存 localStorage）=====
  const _FUDGE_UNLOCK_KEY = 'tianshu_fudge_unlocked';
  // 兑换码（大小写不敏感，校验时统一转大写并去空格）
  const _FUDGE_CODES = ['SK100196'];
  function _isFudgeUnlocked() {
    try { return localStorage.getItem(_FUDGE_UNLOCK_KEY) === '1'; } catch (_) { return false; }
  }
  function _unlockFudge() {
    try { localStorage.setItem(_FUDGE_UNLOCK_KEY, '1'); } catch (_) {}
  }
  function _checkFudgeCode(input) {
    const code = (input || '').trim().toUpperCase();
    return _FUDGE_CODES.includes(code);
  }

function _applyWallpaper(pd) {
  const shell = document.querySelector('#phone-modal .phone-shell');
  if (!shell) return;
  _applyPhoneTheme(shell);
    const isFudge = _getPhoneTheme() === 'fudge';
    const wallpaper = pd?.wallpaper || '';
    // 实色主题（奶油软糖）：允许贴壁纸，但不使用遮罩（遮罩会把 --text 改白，污染图标/卡片配色）
    const useOverlay = isFudge ? false : !!pd?.wallpaperOverlay;
    const opacity = typeof pd?.wallpaperOpacity === 'number' ? Math.max(0, Math.min(100, pd.wallpaperOpacity)) : 75;
    if (wallpaper) {
      shell.style.backgroundImage = useOverlay
        ? `linear-gradient(rgba(0,0,0,0.18), rgba(0,0,0,0.32)), url("${wallpaper}")`
        : `url("${wallpaper}")`;
      // 显式铺满（fudge 主题用 background 简写会把 size 重置成 auto，导致壁纸只铺左上角）
      shell.style.backgroundSize = 'cover';
      shell.style.backgroundPosition = 'center';
    } else {
      shell.style.backgroundImage = '';
      shell.style.backgroundSize = '';
      shell.style.backgroundPosition = '';
    }
    shell.style.setProperty('--phone-card-opacity', String(opacity));
    shell.style.setProperty('--phone-card-opacity-pct', opacity + '%');
    // 深色适配 class：有壁纸 + 开了遮罩才启用（控制卡片黑底白字等 CSS）
    shell.classList.toggle('has-custom-wallpaper', !!wallpaper && useOverlay);
    // 壁纸存在 class：只要有壁纸就加（让底栏半透明）。
    // fudge（奶油软糖）是实色风格，卡片/栏实色到底，不加此 class —— 壁纸只从卡片缝隙透出。
    shell.classList.toggle('has-wallpaper', !!wallpaper && !isFudge);
    // fudge + 壁纸专用钩子：只用于桌面态（.phone-home-mode）复活遮罩 + 把 app 名字染白加阴影，
    // 绝不改 --text（避免污染 app 内图标/卡片配色，这是老遮罩逻辑的坑）。app 内部 fudge 已铺纯底，不受壁纸影响。
    shell.classList.toggle('fudge-has-wallpaper', !!wallpaper && isFudge);
  }

  // ===== 个人资料卡：渲染 + inline 编辑 + 头像 =====
  const PROFILE_DEFAULT = { name: 'Polaris', bio: 'The still point where all worlds turn.', note: 'In silentio vox maxima', avatar: '' };

  function _getProfile(pd) {
    const p = pd?.profile || {};
    return {
      name: typeof p.name === 'string' ? p.name : PROFILE_DEFAULT.name,
      bio: typeof p.bio === 'string' ? p.bio : PROFILE_DEFAULT.bio,
      note: typeof p.note === 'string' ? p.note : PROFILE_DEFAULT.note,
      avatar: typeof p.avatar === 'string' ? p.avatar : ''
    };
  }

  function _applyProfile(pd) {
    const profile = _getProfile(pd);
    const nameEl = document.getElementById('phone-profile-name');
    const bioEl = document.getElementById('phone-profile-bio');
    const avatarEl = document.getElementById('phone-profile-avatar');
    const noteEl = document.getElementById('phone-home-note');
    // 只在不在编辑状态时刷新文字（避免打字时被覆盖）
    if (nameEl && document.activeElement !== nameEl) nameEl.textContent = profile.name || '';
    if (bioEl && document.activeElement !== bioEl) bioEl.textContent = profile.bio || '';
    if (noteEl && document.activeElement !== noteEl) noteEl.textContent = profile.note || '';
    if (avatarEl) {
      if (profile.avatar) {
        avatarEl.style.backgroundImage = `url("${profile.avatar}")`;
        avatarEl.classList.add('has-avatar');
      } else {
        avatarEl.style.backgroundImage = '';
        avatarEl.classList.remove('has-avatar');
      }
    }
  }

  // 字数限制 —— input 时截断超出部分（保持光标在末尾）
  function _onProfileInput(field, el, maxLen) {
    const text = (el.textContent || '');
    if (text.length > maxLen) {
      el.textContent = text.slice(0, maxLen);
      // 把光标放到末尾
      try {
        const range = document.createRange();
        range.selectNodeContents(el);
        range.collapse(false);
        const sel = window.getSelection();
        sel.removeAllRanges();
        sel.addRange(range);
      } catch(_) {}
      UI.showToast(`已达字数上限（${maxLen}）`, 1200);
    }
  }

  function _onProfileFocus(field, el) {
    // 进入编辑：选中所有文字，方便整段替换
    try {
      const range = document.createRange();
      range.selectNodeContents(el);
      const sel = window.getSelection();
      sel.removeAllRanges();
      sel.addRange(range);
    } catch(_) {}
  }

  // 失焦保存
  async function _onProfileBlur(field, el) {
    const raw = (el.textContent || '').trim();
    const value = raw || PROFILE_DEFAULT[field];   // 清空时回落到默认
    if (raw !== value) el.textContent = value;     // 视觉同步
    try {
      const pd = await _getPhoneData();
      if (!pd) return;
      pd.profile = pd.profile || { ...PROFILE_DEFAULT };
      if (pd.profile[field] === value) return;     // 没变化不写
      pd.profile[field] = value;
      await _savePhoneData();
    } catch(e) { console.warn('[Profile] save failed', e); }
  }

  // 回车失焦（不允许换行）
  function _onProfileKeydown(e, field, el) {
    if (e.key === 'Enter') { e.preventDefault(); el.blur(); }
  }

  // 头像：调用通用图片输入弹窗（本地 + URL）
  async function _pickProfileAvatar() {
    if (typeof Utils === 'undefined' || !Utils.promptImageInput) {
      UI.showToast('图片输入组件未就绪', 1500); return;
    }
    try {
      const dataUrl = await Utils.promptImageInput({ maxSize: 256, quality: 0.85, outputFormat: 'jpeg' });
      if (!dataUrl) return;
      const pd = await _getPhoneData();
      if (!pd) return;
      pd.profile = pd.profile || { ...PROFILE_DEFAULT };
      pd.profile.avatar = dataUrl;
      await _savePhoneData();
      _applyProfile(pd);
    } catch(e) { console.warn('[Profile] avatar pick failed', e); UI.showToast('头像设置失败', 1500); }
  }

function _compressWallpaper(file, opts = {}) {
 return new Promise((resolve, reject) => {
 const reader = new FileReader();
 // 动图（gif/webp/apng）走 canvas 会被压成静态首帧，直接原样读 base64 保住动画；静态图才压缩
 const isAnim = /\.(gif|webp|apng)$/i.test(file && file.name || '') || /image\/(gif|webp|apng)/i.test(file && file.type || '');
 if (isAnim) {
 reader.onload = () => resolve(reader.result);
 reader.onerror = reject;
 reader.readAsDataURL(file);
 return;
 }
 reader.onload = () => {
 const img = new Image();
 img.onload = () => {
 const maxW = opts.maxW || 900;
 const maxH = opts.maxH || 1600;
 let { width, height } = img;
 const scale = Math.min(1, maxW / width, maxH / height);
 width = Math.round(width * scale);
 height = Math.round(height * scale);
 const canvas = document.createElement('canvas');
 canvas.width = width;
 canvas.height = height;
 const ctx = canvas.getContext('2d');
 ctx.drawImage(img,0,0, width, height);
 resolve(canvas.toDataURL('image/jpeg', opts.quality || 0.82));
 };
 img.onerror = reject;
 img.src = reader.result;
 };
 reader.onerror = reject;
 reader.readAsDataURL(file);
 });
}

// ===== 外壳渲染 =====
  async function open() {
    if (!_isAnyWorldview()) { UI.showToast('请先选择一个世界观', 1500); return; }
    // 心动模拟：被 char 锁定时不允许打开
    try {
      if (typeof StatusBar !== 'undefined' && StatusBar.isPhoneLocked && StatusBar.isPhoneLocked()) {
        const info = StatusBar.getPhoneLockInfo?.();
        const by = info?.lockedBy || '心动目标';
        UI.showToast(`手机被${by}锁起来了，拿不到`, 2500);
        return;
      }
    } catch(_) {}
    let modal = document.getElementById('phone-modal');
    if (!modal) _createModal();
    modal = document.getElementById('phone-modal');
    _currentApp = null;
    // 加载世界观对商城 App 的自定义（影响首页图标名字和商城 prompt）
    try { await _loadShopMeta(); } catch(_) {}
    // 预热世界观 gameplay：让钱包等同步函数能 fallback 到世界观属性定义
    try { await _prewarmWvGameplay(); } catch(_) {}
    _renderHomeScreen();
    modal.classList.remove('hidden');
    _isOpen = true;
 _hasNewNotif = false;
 _startBatteryTicker();
 // 打开手机时隐藏悬浮按钮
    document.getElementById('phone-fab')?.classList.add('hidden');
  }

  function close() {
    // 番茄钟锁屏：运行中不允许关闭手机
    if (_tomatoTimer && _tomatoIsLocked()) {
      UI.showToast('专注中，屏幕已锁定', 1500);
      return;
    }
    const modal = document.getElementById('phone-modal');
    if (modal) modal.classList.add('hidden');
_isOpen = false;
 _currentApp = null;
 _stopBatteryTicker();
 //关闭后显示悬浮按钮（和风闻 minimize 一样的行为）
    const fab = document.getElementById('phone-fab');
    // 心动模拟锁机时也不显示悬浮按钮
    let _locked = false;
    try { _locked = !!(typeof StatusBar !== 'undefined' && StatusBar.isPhoneLocked && StatusBar.isPhoneLocked()); } catch(_) {}
    if (fab && _isAnyWorldview() && !_locked) {
      fab.classList.remove('hidden');
      _updateFab();
    } else if (fab && _locked) {
      fab.classList.add('hidden');
    }

    // phoneDown 入口A：手机关闭时，如果有 pending 且用户在聊天页且不在 streaming，直接触发
    if (_pendingPhoneDown) {
      try {
        const chatPanel = document.querySelector('#panel-chat.active');
        const canTrigger = chatPanel && typeof Chat !== 'undefined' && !Chat.isStreamingNow();
        if (canTrigger) {
          setTimeout(() => {
            try {
              if (!_pendingPhoneDown) return;
              const input = document.getElementById('chat-input');
              if (input && !Chat.isStreamingNow()) { input.value = '<PhoneDown/>'; Chat.send(); }
            } catch(_) {}
          }, 500);
        }
      } catch(_) {}
    }
  }

  function minimize() {
 close();
}

function isOpen() { return _isOpen; }

function _isAppStillActive(appId) {
 return _isOpen && _currentApp === appId && !!document.getElementById('phone-body');
}

  function _formatNpcMomentFullLog(m, operation) {
    const lines = [];
    lines.push(`用户${operation}了一条好友动态：`);
    lines.push(`发布者：${m?.npc || '未知'}`);
    if (m?.time) lines.push(`发布时间：${m.time}`);
    lines.push(`正文：${m?.text || ''}`);
    const comments = Array.isArray(m?.comments) ? m.comments : [];
    if (comments.length > 0) {
      lines.push('评论区：');
      comments.forEach(c => lines.push(`- ${c.name || '未知'}：${c.text || ''}`));
    } else {
      lines.push('评论区：暂无');
    }
    return lines.join('\n');
  }

  // ===== 构建完整上下文（供论坛/地图/好友圈 AI 调用共用） =====
  async function _buildFullContext(opts) {
    const npcBrief = !!(opts && opts.npcBrief);
    // lite 模式（连线夜话专用）：跳过玩家面具/住所/单人卡主角/挂载角色，
    // 只保留世界观基础+时间+节日+知识+速查表+10轮主线。其它调用方不传则行为不变。
    const lite = !!(opts && opts.lite);
    // castFilter（电台/阅读「可出场角色」专用，纯可选）：控制 NPC 详情输出。
    //   { mode:'disabled' } 完全不发任何 NPC；{ mode:'whitelist', ids:Set } 只发名单内 NPC。
    //   不传则行为完全不变。仅作用于完整模式（npcBrief:false）的 NPC 详情块。
    const castFilter = (opts && opts.castFilter && (opts.castFilter.mode === 'disabled' || opts.castFilter.mode === 'whitelist'))
      ? { mode: opts.castFilter.mode, ids: (opts.castFilter.ids instanceof Set) ? opts.castFilter.ids : new Set(Array.isArray(opts.castFilter.ids) ? opts.castFilter.ids : []), allowLorebook: !!opts.castFilter.allowLorebook }
      : null;
    // includeConvChars（电台/阅读专用，纯可选）：lite 模式下也补发当前对话的单人卡主角 + 挂载角色。
    //   不传则行为不变。返航(_hsSkipNpc)模式始终不补发。
    const includeConvChars = !!(opts && opts.includeConvChars);
    const parts = [];

    // v687.33：心动模拟返航后，根据 hsPostHomeMode 决定如何构建世界观/NPC 数据
    //   - continue（继续日常）：完全替换为返航世界设定，屏蔽所有 NPC/节日，保留知识（钩子通道）
    //   - epilogue（第二部钩子已触发）：与 continue 一致——屏蔽所有 NPC，剧情已彻底结束
    //   - end（到此结束）/ 未选择：保留原版，方便复盘
    let _hsHomecomingActive = false;
    let _hsPostHomeMode = null;
    let _phonePd = null;
    try {
      const pd = await _getPhoneData();
      _phonePd = pd;
      _hsHomecomingActive = !!(pd && pd.hsHomecomingTriggered);
      _hsPostHomeMode = pd?.hsPostHomeMode || null;
    } catch(_) {}
    // 手机注入开关（只控世界观自带的扩展设定，默认全开；世界书来的不受影响）
    const _injFest = !(_phonePd && _phonePd.injectFestival === false);
    const _injCustom = !(_phonePd && _phonePd.injectCustom === false);
    const _injKnowledge = !(_phonePd && _phonePd.injectKnowledge === false);
    const _hsSkipNpc = _hsHomecomingActive && (_hsPostHomeMode === 'continue' || _hsPostHomeMode === 'epilogue' || _hsPostHomeMode === 'companion');

    // 1. 世界观基础设定
    if (_hsSkipNpc) {
      // 返航 continue/epilogue/companion 模式：替换为现实世界设定
      parts.push('【返航后·世界观设定】\n这是一个与现实世界几乎完全一致的当代世界。科技水平、社会制度、文化背景、地理格局均与当今现实相同。没有超自然现象，没有异世界，没有任何违反常识的事物存在。\n人们正常地生活、工作、社交。城市有便利店和地铁，手机能刷短视频和点外卖，天气预报偶尔不准，快递偶尔送错地址。一切都按照普通的现代社会运转。');
    } else {
      const wvPrompt = Chat.getWorldviewPrompt() || '';
      if (wvPrompt) parts.push('【世界观设定】\n' + wvPrompt);
    }

    // 1.5 当前游戏时间（统一给论坛 / 好友圈 / 地图等 AI 生成内容使用）
    try {
      const sb = Conversations.getStatusBar();
      if (sb?.time) parts.push('【当前游戏时间】\n' + _formatPhoneTime(sb.time));
    } catch(_) {}

    // 2. 世界观详细数据（NPC、节日、自定义设定）
    try {
      const wv = await Worldview.getCurrent();

      // v687.6：聚合所有绑定的世界书（按对话/卡/世界观/挂载角色）
      let bookExtra = { globalNpcs: [], festivals: [], knowledges: [] };
      try {
        if (typeof Lorebook !== 'undefined' && Lorebook.collectForChat) {
          const conv = (typeof Conversations !== 'undefined') ? Conversations.getList().find(c => c.id === Conversations.getCurrent()) : null;
          let card = null;
          if (conv && conv.isSingle && conv.singleCharType === 'card' && conv.singleCharId) {
            try { card = await DB.get('singleCards', conv.singleCharId); } catch(_) {}
          }
          // 手机视角的世界书：默认沿用主线挂的，叠加手机单独加的（phoneLorebookIds），
          // 再叠加手机单独关的（phoneLorebookDisabled）——只影响手机，主线 conv 不动
          const _phoneAdd = (_phonePd && Array.isArray(_phonePd.phoneLorebookIds)) ? _phonePd.phoneLorebookIds : [];
          const _phoneOff = (_phonePd && Array.isArray(_phonePd.phoneLorebookDisabled)) ? _phonePd.phoneLorebookDisabled : [];
          const phoneConv = conv
            ? { ...conv, lorebookIds: [...(conv.lorebookIds || []), ..._phoneAdd], lorebookDisabled: [...(conv.lorebookDisabled || []), ..._phoneOff] }
            : { lorebookIds: _phoneAdd.slice(), lorebookDisabled: _phoneOff.slice() };
          const lbs = await Lorebook.collectForChat({ conv: phoneConv, card, wv });
          for (const lb of (lbs || [])) {
            if (Array.isArray(lb.globalNpcs)) bookExtra.globalNpcs.push(...lb.globalNpcs);
            if (Array.isArray(lb.festivals)) bookExtra.festivals.push(...lb.festivals);
            if (Array.isArray(lb.knowledges)) bookExtra.knowledges.push(...lb.knowledges);
          }
        }
      } catch(_) {}

      if (wv) {
        // v687.33：返航 continue/epilogue 模式下屏蔽所有 NPC 和节日（那些角色和事件在这个世界不存在）
        if (_hsSkipNpc) {
          // 知识设定保留——是钩子通道
          const allKnowledges = [...(wv.knowledges || wv.customs || []), ...bookExtra.knowledges];
          if (allKnowledges.length > 0) {
            const enabledAll = allKnowledges.filter(c => c.enabled !== false);
            if (enabledAll.length > 0) {
              const custStr = enabledAll.map(c => `${c.name || ''}：${c.content || ''}`).join('\n');
              parts.push('【知识设定】\n' + custStr);
            }
          }
        } else {
        // 全图 NPC + 详细资料（世界观 + 世界书合并）
        if (npcBrief) {
          // brief 模式：世界观 NPC 只发速查表，不发详细资料
          try {
            const quickRef = NPC.formatQuickRef();
            if (quickRef) parts.push(quickRef);
          } catch(_) {}
          // 世界书 NPC brief 模式：只发名字+别名，不发 detail（避免串味）
          if (bookExtra.globalNpcs.length > 0) {
            const lines = bookExtra.globalNpcs.map(npc => {
              let d = npc.name || '未命名';
              if (npc.aliases) d += `（别名：${npc.aliases}）`;
              return d;
            });
            parts.push('【世界书角色索引】\n' + lines.join('\n'));
          }
        } else {
        // 完整模式：全图 NPC + 详细资料（世界观 + 世界书合并）
        const allNpcs = [];
        // castFilter：disabled 整块跳过；whitelist 只收名单内 id
        const _castAllow = (npc, isLorebook) => {
          if (!castFilter) return true;
          if (castFilter.mode === 'disabled') return false;
          // whitelist：勾选了"世界书角色"时，世界书来源的 NPC 整体放行
          if (isLorebook && castFilter.allowLorebook) return true;
          return !!(npc && npc.id && castFilter.ids.has(npc.id));
        };
        const collectNpc = (npc, regionName, isLorebook) => {
          if (!_castAllow(npc, isLorebook)) return;
          let desc = `${npc.name || '未命名'}`;
          if (regionName) desc += `（所属：${regionName}）`;
          if (npc.aliases) desc += `（别名：${npc.aliases}）`;
          if (npc.detail) desc += `\n${npc.detail}`;
          allNpcs.push(desc);
        };
        if (wv.globalNpcs && wv.globalNpcs.length > 0) {
          for (const npc of wv.globalNpcs) collectNpc(npc, '');
        }
        // 地区/势力挂载 NPC
        if (wv.regions && wv.regions.length > 0) {
          for (const r of wv.regions) {
            if (r.npcs && r.npcs.length > 0) {
              for (const npc of r.npcs) collectNpc(npc, r.name || '未知');
            }
          }
        }
        // v687.6：世界书 NPC（合并到列表，去重按 id）
        if (bookExtra.globalNpcs.length > 0) {
          const seenIds = new Set();
          (wv.globalNpcs || []).forEach(n => { if (n.id) seenIds.add(n.id); });
          (wv.regions || []).forEach(r => (r.npcs || []).forEach(n => { if (n.id) seenIds.add(n.id); }));
          for (const npc of bookExtra.globalNpcs) {
            if (npc.id && seenIds.has(npc.id)) continue;
            collectNpc(npc, '', true);
          }
        }
        if (allNpcs.length > 0) parts.push('【NPC列表与详细资料】\n' + allNpcs.join('\n---\n'));
        }

        // 节日设定（世界观 + 世界书合并）— 世界观部分受手机开关控制，世界书部分不受影响
        const allFest = [...(_injFest ? (wv.festivals || []) : []), ...bookExtra.festivals];
        if (allFest.length > 0) {
          const festStr = allFest.map(f => `${f.name || ''}（${f.date || ''}）：${f.content || ''}`).join('\n');
          parts.push('【节日设定】\n' + festStr);
        }

        // 知识设定（世界观 + 世界书合并）— v687.6：所有启用条目都进，不再区分关键词触发
        // 世界观部分按手机开关分常驻(keywordTrigger=false)/动态(true)过滤；世界书部分不受影响
        const wvKnowledges = (wv.knowledges || wv.customs || []).filter(c => {
          if (c && c.keywordTrigger) return _injKnowledge;
          return _injCustom;
        });
        const allKnowledges = [...wvKnowledges, ...bookExtra.knowledges];
        if (allKnowledges.length > 0) {
          const enabledAll = allKnowledges.filter(c => c.enabled !== false);
          if (enabledAll.length > 0) {
            const custStr = enabledAll.map(c => `${c.name || ''}：${c.content || ''}`).join('\n');
            parts.push('【知识设定】\n' + custStr);
          }
        }
        } // v687.33: end of !_hsSkipNpc 分支
      } else if (bookExtra.globalNpcs.length || bookExtra.festivals.length || bookExtra.knowledges.length) {
        // 没世界观但有世界书（单人卡 + 世界书的场景）
        // castFilter 同样生效：disabled 时一律不发世界书角色；whitelist 时只发名单内（或 allowLorebook 全放）。
        if (bookExtra.globalNpcs.length > 0) {
          const allow = (npc) => {
            if (!castFilter) return true;
            if (castFilter.mode === 'disabled') return false;
            if (castFilter.allowLorebook) return true;
            return !!(npc && npc.id && castFilter.ids.has(npc.id));
          };
          const allowed = bookExtra.globalNpcs.filter(allow);
          if (allowed.length > 0) {
            const lines = allowed.map(npc => {
              let d = npc.name || '未命名';
              if (npc.aliases) d += `（别名：${npc.aliases}）`;
              // brief 模式只发名字+别名，不发 detail
              if (!npcBrief && npc.detail) d += `\n${npc.detail}`;
              return d;
            });
            parts.push((npcBrief ? '【世界书角色索引】\n' : '【NPC列表与详细资料】\n') + lines.join(npcBrief ? '\n' : '\n---\n'));
          }
        }
        if (bookExtra.festivals.length > 0) {
          parts.push('【节日设定】\n' + bookExtra.festivals.map(f => `${f.name || ''}（${f.date || ''}）：${f.content || ''}`).join('\n'));
        }
        const enabledAll = bookExtra.knowledges.filter(c => c.enabled !== false);
        if (enabledAll.length > 0) {
          parts.push('【知识设定】\n' + enabledAll.map(c => `${c.name || ''}：${c.content || ''}`).join('\n'));
        }
      }
    } catch(e) { console.warn('[Phone] 世界观/世界书数据获取失败', e); }

    // 3. 用户面具信息
    if (!lite) try {
      const mask = await Character.get();
      if (mask && mask.name) {
        let maskStr = `名字：${mask.name}`;
        if (mask.onlineName) maskStr += `\n网名：${mask.onlineName}`;
        // 兼容历史字段名：实际数据字段是 background；老代码写的 description/personality 实际从未存在
        const bg = mask.background || mask.description || '';
        if (bg) maskStr += `\n设定：${bg}`;
        parts.push('【⚠ 玩家角色基本设定（必须严格遵守，所有涉及玩家性别/外貌/身份的描写都以此为准）】\n' + maskStr);
      }
    } catch(_) {}

    // 3.1 当前居住的住所信息
    if (!lite) try {
      const _pd = await _getPhoneData();
      if (_pd && Array.isArray(_pd.houses)) {
        const curHouse = _pd.houses.find(h => h.isCurrent);
        if (curHouse && curHouse.name) {
          let hStr = `住所名称：${curHouse.name}`;
          if (curHouse.region) hStr += `\n所在地区：${curHouse.region}`;
          if (curHouse.address) hStr += `\n具体地址：${curHouse.address}`;
          if (curHouse.styleDesc) hStr += `\n装修风格：${curHouse.styleDesc}`;
          parts.push('【玩家当前居住地】\n' + hStr);
        }
      }
    } catch(_) {}

    // 3.5 v617：当前对话绑定的单人卡主角（AI 扮演角色）
    // v687.33：返航 continue/epilogue 模式下跳过（单人卡主角不属于返航后的现实世界）
    // includeConvChars：电台/阅读预览在 lite 下也带上（受 castFilter 约束：disabled 不发，whitelist 需 id 命中）
    if (!_hsSkipNpc && (!lite || includeConvChars)) try {
      const conv = (typeof Conversations !== 'undefined') ? Conversations.getList().find(c => c.id === Conversations.getCurrent()) : null;
      // castFilter 约束：disabled 全不发；whitelist 仅当该角色 id 在名单内才发
      const _convCharAllow = (id) => {
        if (!castFilter) return true;
        if (castFilter.mode === 'disabled') return false;
        return !!(id && castFilter.ids.has(id));
      };
      if (conv && conv.isSingle && conv.singleCharType === 'card' && conv.singleCharId && _convCharAllow(conv.singleCharId)) {
        const card = await DB.get('singleCards', conv.singleCharId);
        if (card && card.name) {
          let cardStr = `姓名：${card.name}`;
          if (card.aliases) cardStr += `\n别名：${card.aliases}`;
          if (card.detail) cardStr += `\n设定：${card.detail}`;
          parts.push('【当前对话主角（AI 扮演角色）】\n' + cardStr);
        }
      } else if (conv && conv.isSingle && conv.singleCharType === 'npc' && conv.singleCharId && _convCharAllow(conv.singleCharId)) {
        // 单人·NPC 模式：从 worldviews 里查
        try {
          const wvs = await DB.getAll('worldviews');
          for (const wv of wvs) {
            if (!wv) continue;
            let found = null;
            (wv.globalNpcs || []).forEach(n => { if (n.id === conv.singleCharId) found = n; });
            (wv.regions || []).forEach(r => (r.factions || []).forEach(f => (f.npcs || []).forEach(n => { if (n.id === conv.singleCharId) found = n; })));
            if (found) {
              let s = `姓名：${found.name || '未命名'}`;
              if (found.aliases) s += `\n别名：${found.aliases}`;
              if (found.detail) s += `\n设定：${found.detail}`;
              parts.push('【当前对话主角（AI 扮演角色）】\n' + s);
              break;
            }
          }
        } catch(_) {}
      }
    } catch(_) {}

    // 3.6 v617：对话级挂载角色（拉郎 / 客串 / 常驻）
    // v687.33：返航 continue/epilogue 模式下跳过（挂载角色也不属于返航后的现实世界）
    // includeConvChars：电台/阅读预览在 lite 下也带上（受 castFilter 约束）
    if (!_hsSkipNpc && (!lite || includeConvChars)) try {
      if (typeof AttachedChars !== 'undefined' && AttachedChars.resolveAll) {
        let attached = await AttachedChars.resolveAll();
        if (attached && attached.length > 0) {
          // castFilter 约束：disabled 全不发；whitelist 仅保留 id 在名单内的
          if (castFilter) {
            if (castFilter.mode === 'disabled') attached = [];
            else attached = attached.filter(c => c && c.id && castFilter.ids.has(c.id));
          }
        }
        if (attached && attached.length > 0) {
          const attStrs = attached.map(c => {
            let s = `${c.name || '未命名'}`;
            if (c.aliases) s += `（别名：${c.aliases}）`;
            if (c.detail) s += `\n${c.detail}`;
            return s;
          });
          parts.push('【临时加入的角色（挂载角色）】\n以下角色是玩家临时挂载到本对话的，和世界观 NPC 一样可以作为帖子/动态的发布者或评论者。玩家可能就是喜欢这几个角色才挂载进来的，按剧情需要自然安排他们出场。\n' + attStrs.join('\n---\n'));
        }
      }
    } catch(_) {}

    // 4. 最近10轮主线对话记录（skipMainline=true 时跳过，由调用方自己精细拼，如用户自播）
    if (!(opts && opts.skipMainline)) try {
      const msgs = Chat.getMessages() || [];
      const recent = msgs.filter(m => !m.hidden).slice(-20); // 取最后20条消息≈10轮
      if (recent.length > 0) {
        const histStr = recent.map(m => {
          const role = m.role === 'user' ? '玩家' : 'AI';
          const text = (m.content || '').substring(0, 300);
          return `[${role}] ${text}${(m.content || '').length > 300 ? '…' : ''}`;
        }).join('\n');
        parts.push('【最近主线剧情（供参考）】\n' + histStr);
      }
    } catch(_) {}

    return parts.join('\n\n');
  }

  // ===== 加载态跟踪（所有正在跑的任务共享这个计数） =====
  let _generatingCount = 0;
  function _setFabGenerating(on) {
    if (on) _generatingCount++;
    else _generatingCount = Math.max(0, _generatingCount - 1);
    const fab = document.getElementById('phone-fab');
    if (fab) fab.classList.toggle('generating', _generatingCount > 0);
  }
function _extractJsonArrayText(content) {
    const text = String(content || '').replace(/```(?:json)?/gi, '').replace(/```/g, '').trim();
    const directStart = text.indexOf('[');
    if (directStart >= 0) {
      let depth = 0;
      let inStr = false;
      let esc = false;
      for (let i = directStart; i < text.length; i++) {
        const ch = text[i];
        if (inStr) {
          if (esc) esc = false;
          else if (ch === '\\') esc = true;
          else if (ch === '"') inStr = false;
          continue;
        }
        if (ch === '"') { inStr = true; continue; }
        if (ch === '[') depth++;
        else if (ch === ']') {
          depth--;
          if (depth === 0) return text.slice(directStart, i + 1);
        }
      }
      // 括号没配平到底（常见于被 max_tokens 截断）：回退到最后一个 ] 处截取，
      // 保住前面已完整的对象，总比整段判失败强。
      const lastClose = text.lastIndexOf(']');
      if (lastClose > directStart) return text.slice(directStart, lastClose + 1);
    }
    const wrapped = text.match(/"(?:results|data|items)"\s*:\s*(\[[\s\S]*\])/i);
    return wrapped ? _extractJsonArrayText(wrapped[1]) : '';
  }

  // 逐个对象抠取兜底：当整体 JSON.parse 失败时，用括号配平把数组里一个个 {...} 抠出来，
  // 逐个尝试解析，能解析几条算几条（好友圈少几条 >> 整个失败）。
  function _salvageJsonObjects(arrText) {
    const out = [];
    const s = String(arrText || '');
    let i = 0;
    while (i < s.length) {
      if (s[i] !== '{') { i++; continue; }
      // 从这个 { 开始做括号配平，找到匹配的 }
      let depth = 0, inStr = false, esc = false, start = i;
      for (; i < s.length; i++) {
        const ch = s[i];
        if (inStr) {
          if (esc) esc = false;
          else if (ch === '\\') esc = true;
          else if (ch === '"') inStr = false;
          continue;
        }
        if (ch === '"') { inStr = true; continue; }
        if (ch === '{') depth++;
        else if (ch === '}') {
          depth--;
          if (depth === 0) {
            const objText = s.slice(start, i + 1);
            try {
              out.push(JSON.parse(objText));
            } catch (_) {
              try { out.push(JSON.parse(objText.replace(/,\s*([}\]])/g, '$1'))); } catch (_) {}
            }
            i++;
            break;
          }
        }
      }
    }
    return out;
  }

  function _parsePhoneJsonArray(content) {
    const arrText = _extractJsonArrayText(content);
    if (!arrText) throw new Error('返回格式不正确');
    // 1) 直接解析
    try {
      const parsed = JSON.parse(arrText);
      if (Array.isArray(parsed)) return parsed;
    } catch (_) {}
    // 2) 修尾逗号后再解析
    try {
      const parsed = JSON.parse(arrText.replace(/,\s*([}\]])/g, '$1'));
      if (Array.isArray(parsed)) return parsed;
    } catch (_) {}
    // 3) 全角逗号归一化后再解析（保守：仅在前两步失败后才动；
    //    不动中文引号，避免误伤动态正文里本就含有的 “ ” 引号）
    try {
      const normalized = arrText
        .replace(/\uFF0C/g, ',')             // 全角逗号 → 半角
        .replace(/,\s*([}\]])/g, '$1');     // 顺手修尾逗号
      const parsed = JSON.parse(normalized);
      if (Array.isArray(parsed)) return parsed;
    } catch (_) {}
    // 4) 逐个对象抠取兜底：能救几条算几条
    const salvaged = _salvageJsonObjects(arrText);
    if (salvaged.length > 0) return salvaged;
    throw new Error('返回内容不是数组');
  }

  // 解析单个 JSON 对象（论坛帖子详情等用）：剥 markdown → 括号配平提取首个 {...} →
  // 直接解析 → 修尾逗号 → 全角逗号归一化，逐级兜底。全失败抛错。
  function _parsePhoneJsonObject(content) {
    const text = String(content || '').replace(/```(?:json)?/gi, '').replace(/```/g, '').trim();
    const start = text.indexOf('{');
    if (start < 0) throw new Error('返回格式不正确');
    let objText = '';
    {
      let depth = 0, inStr = false, esc = false;
      for (let i = start; i < text.length; i++) {
        const ch = text[i];
        if (inStr) {
          if (esc) esc = false;
          else if (ch === '\\') esc = true;
          else if (ch === '"') inStr = false;
          continue;
        }
        if (ch === '"') { inStr = true; continue; }
        if (ch === '{') depth++;
        else if (ch === '}') { depth--; if (depth === 0) { objText = text.slice(start, i + 1); break; } }
      }
      // 没配平到底（被截断）：回退到最后一个 } 处
      if (!objText) {
        const lastClose = text.lastIndexOf('}');
        objText = lastClose > start ? text.slice(start, lastClose + 1) : text.slice(start);
      }
    }
    try { return JSON.parse(objText); } catch (_) {}
    try { return JSON.parse(objText.replace(/,\s*([}\]])/g, '$1')); } catch (_) {}
    try { return JSON.parse(objText.replace(/\uFF0C/g, ',').replace(/,\s*([}\]])/g, '$1')); } catch (_) {}
    throw new Error('返回格式不正确');
  }

  // 带超时的 fetch：默认 90 秒。超时会 abort 请求并抛出可识别的超时错误，
  // 避免中转站 hold 住非流式大请求不返回时无限挂起（直播/商城等大批量生成场景）。
  async function _phoneFetchWithTimeout(url, options, timeoutMs) {
    const ms = Number.isFinite(timeoutMs) ? timeoutMs : 90000;
    const ctrl = new AbortController();
    const timer = setTimeout(() => { try { ctrl.abort(); } catch (_) {} }, ms);
    try {
      return await fetch(url, { ...options, signal: ctrl.signal });
    } catch (e) {
      if (e && e.name === 'AbortError') throw new Error(`请求超时（${Math.round(ms / 1000)}秒未响应）`);
      throw e;
    } finally {
      clearTimeout(timer);
    }
  }

  async function _phoneJsonArrayWithRetry(opts) {
    const {
      label = '手机内容', url, key, model, messages,
      temperature = 0.9, max_tokens = 2048,
      onAttempt
    } = opts || {};
    // 默认最多重试 3 次；若对话设置关闭了自动重试则只跑一次
    const baseMax = (opts && Number.isFinite(opts.maxRetries)) ? opts.maxRetries : 3;
    const maxRetries = (typeof Chat !== 'undefined' && Chat.isRetryDisabled && Chat.isRetryDisabled()) ? 1 : baseMax;
    let lastError = '';
    let lastContent = '';
    for (let attempt = 1; attempt <= maxRetries; attempt++) {
      try {
        if (typeof onAttempt === 'function') onAttempt(attempt, maxRetries);
        const strictMessages = attempt === 1 ? messages : [
          ...(messages || []),
          { role: 'system', content: '上一次返回无法解析。请立刻重新输出严格 JSON 数组：只能输出以 [ 开头、以 ] 结尾的 JSON；不要 Markdown；不要解释；不要代码块；字符串必须使用英文双引号。' }
        ];
        const resp = await _phoneFetchWithTimeout(url, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${key}` },
          body: JSON.stringify({ model, messages: strictMessages, stream: false, temperature, max_tokens })
        });
        if (!resp.ok) throw new Error(`API错误: ${resp.status}`);
        const json = await resp.json();
        const content = _phoneExtractContent(json);
        lastContent = content;
        return _parsePhoneJsonArray(content);
      } catch(e) {
        lastError = e.message || String(e);
        console.error(`[Phone] ${label} attempt ${attempt} failed:`, e, lastContent ? { content: lastContent } : '');
        if (attempt < maxRetries) {
          UI.showToast(`${label}生成失败，正在重试…（${attempt + 1}/${maxRetries}）`, 1600);
          await new Promise(r => setTimeout(r, 900));
        }
      }
    }
    throw new Error(lastError || '生成失败');
  }

  // 从 API 响应的 message 里取正文：content 为空时（thinking 模型常见）回退到其它字符串字段。
  function _phoneExtractContent(json) {
    const msg = (json && json.choices && json.choices[0] && json.choices[0].message) || {};
    let text = (msg.content || '');
    if (typeof text === 'string') text = text.trim();
    else text = '';
    if (!text) {
      for (const k of Object.keys(msg)) {
        if (k === 'role' || k === 'refusal' || k === 'tool_calls' || k === 'reasoning_content') continue;
        const v = msg[k];
        if (typeof v === 'string' && v.trim().length > 5) { text = v.trim(); break; }
      }
    }
    return text;
  }

  // 同上，但解析单个 JSON 对象（故事蓝图等用）。失败重试，全失败抛错。
  async function _phoneJsonObjectWithRetry(opts) {
    const {
      label = '手机内容', url, key, model, messages,
      temperature = 0.9, max_tokens = 2048,
      onAttempt
    } = opts || {};
    const baseMax = (opts && Number.isFinite(opts.maxRetries)) ? opts.maxRetries : 3;
    const maxRetries = (typeof Chat !== 'undefined' && Chat.isRetryDisabled && Chat.isRetryDisabled()) ? 1 : baseMax;
    let lastError = '';
    let lastContent = '';
    for (let attempt = 1; attempt <= maxRetries; attempt++) {
      try {
        if (typeof onAttempt === 'function') onAttempt(attempt, maxRetries);
        const strictMessages = attempt === 1 ? messages : [
          ...(messages || []),
          { role: 'system', content: '上一次返回无法解析。请立刻重新输出严格 JSON 对象：只能输出以 { 开头、以 } 结尾的 JSON；不要 Markdown；不要解释；不要代码块；字符串必须使用英文双引号。' }
        ];
        const resp = await _phoneFetchWithTimeout(url, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${key}` },
          body: JSON.stringify({ model, messages: strictMessages, stream: false, temperature, max_tokens })
        });
        if (!resp.ok) throw new Error(`API错误: ${resp.status}`);
        const json = await resp.json();
        const content = _phoneExtractContent(json);
        lastContent = content;
        return _parsePhoneJsonObject(content);
      } catch(e) {
        lastError = e.message || String(e);
        console.error(`[Phone] ${label} attempt ${attempt} failed:`, e, lastContent ? { content: lastContent } : '');
        if (attempt < maxRetries) {
          UI.showToast(`${label}生成失败，正在重试…（${attempt + 1}/${maxRetries}）`, 1600);
          await new Promise(r => setTimeout(r, 900));
        }
      }
    }
    throw new Error(lastError || '生成失败');
  }

  // 纯文本生成（章节正文等用），不做 JSON 解析，直接返回文本。失败重试，全失败抛错。
  async function _phoneTextWithRetry(opts) {
    const {
      label = '手机内容', url, key, model, messages,
      temperature = 0.9, max_tokens = 4096,
      onAttempt
    } = opts || {};
    const baseMax = (opts && Number.isFinite(opts.maxRetries)) ? opts.maxRetries : 3;
    const maxRetries = (typeof Chat !== 'undefined' && Chat.isRetryDisabled && Chat.isRetryDisabled()) ? 1 : baseMax;
    let lastError = '';
    for (let attempt = 1; attempt <= maxRetries; attempt++) {
      try {
        if (typeof onAttempt === 'function') onAttempt(attempt, maxRetries);
        const resp = await _phoneFetchWithTimeout(url, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${key}` },
          body: JSON.stringify({ model, messages, stream: false, temperature, max_tokens })
        });
        if (!resp.ok) throw new Error(`API错误: ${resp.status}`);
        const json = await resp.json();
        const content = _phoneExtractContent(json);
        if (!content) throw new Error('返回为空');
        return content;
      } catch(e) {
        lastError = e.message || String(e);
        console.error(`[Phone] ${label} attempt ${attempt} failed:`, e);
        if (attempt < maxRetries) {
          UI.showToast(`${label}生成失败，正在重试…（${attempt + 1}/${maxRetries}）`, 1600);
          await new Promise(r => setTimeout(r, 900));
        }
      }
    }
    throw new Error(lastError || '生成失败');
  }
  function _updateFab() {
    const fab = document.getElementById('phone-fab');
    if (!fab) return;
    const dot = fab.querySelector('.phone-notif-dot');
    if (dot) dot.style.display = _hasNewNotif && !_isOpen ? '' : 'none';
  }

  // 对外：按当前条件同步手机悬浮球显隐（刷新/启动/切对话时调用，恢复常驻）
  // 条件与 close() 一致：有世界观 + 未锁机 + 手机未打开 + 在聊天面板
  function syncFab() {
    const fab = document.getElementById('phone-fab');
    if (!fab) return;
    if (_isOpen) { fab.classList.add('hidden'); return; }
    let _locked = false;
    try { _locked = !!(typeof StatusBar !== 'undefined' && StatusBar.isPhoneLocked && StatusBar.isPhoneLocked()); } catch(_) {}
    const chatActive = document.querySelector('#panel-chat.active');
    if (_isAnyWorldview() && !_locked && chatActive) {
      fab.classList.remove('hidden');
      _updateFab();
    } else {
      fab.classList.add('hidden');
    }
  }

  function setNotification(flag) {
    _hasNewNotif = flag;
    _updateFab();
  }

  // 通用顶部横幅提示：背景色底 + 头像 + 内容预览，无边框无渐变，可点击跳转
  // opts: { avatarInner（头像 html，img 或首字母）, title, text, onClick }
  let _phoneBannerTimer = null;
  function _showPhoneTopBanner(opts) {
    opts = opts || {};
    const shell = document.querySelector('#phone-modal .phone-shell');
    if (!shell) return;
    // 移除旧横幅
    shell.querySelector('#phone-top-banner')?.remove();
    if (_phoneBannerTimer) { clearTimeout(_phoneBannerTimer); _phoneBannerTimer = null; }

    const banner = document.createElement('div');
    banner.id = 'phone-top-banner';
    banner.style.cssText = 'position:absolute;top:0;left:0;right:0;z-index:10000;margin:8px 10px;padding:10px 12px;background:var(--bg);border-radius:14px;box-shadow:0 4px 16px rgba(0,0,0,0.18);display:flex;align-items:center;gap:10px;cursor:pointer;transform:translateY(-130%);transition:transform 0.28s cubic-bezier(0.2,0.8,0.3,1)';
    banner.innerHTML = `
      <div style="width:38px;height:38px;border-radius:50%;flex-shrink:0;background:var(--accent);color:var(--bg);display:flex;align-items:center;justify-content:center;font-size:15px;font-weight:600;overflow:hidden">${opts.avatarInner || ''}</div>
      <div style="flex:1;min-width:0">
        <div style="font-size:13px;font-weight:600;color:var(--text);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${Utils.escapeHtml(opts.title || '')}</div>
        <div style="font-size:12px;color:var(--text-secondary);margin-top:2px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${Utils.escapeHtml(opts.text || '')}</div>
      </div>`;

    const dismiss = () => {
      if (_phoneBannerTimer) { clearTimeout(_phoneBannerTimer); _phoneBannerTimer = null; }
      banner.style.transform = 'translateY(-130%)';
      setTimeout(() => { try { banner.remove(); } catch(_) {} }, 300);
    };
    banner.onclick = () => {
      dismiss();
      try { if (typeof opts.onClick === 'function') opts.onClick(); } catch(_) {}
    };

    shell.appendChild(banner);
    // 触发滑入动画
    requestAnimationFrame(() => { banner.style.transform = 'translateY(0)'; });
    // 4 秒后自动收起
    _phoneBannerTimer = setTimeout(dismiss, 4000);
  }

  // ===== Modal 创建 =====
  function _createModal() {
    const modal = document.createElement('div');
    modal.id = 'phone-modal';
    modal.className = 'hidden';
    modal.style.cssText = 'position:fixed;inset:0;z-index:500;display:flex;align-items:center;justify-content:center;background:rgba(0,0,0,0.38);backdrop-filter:blur(8px)';
    modal.onclick = (e) => { if (e.target === modal) close(); };
 modal.innerHTML = `
 <div class="phone-shell" onclick="event.stopPropagation()">
 <div class="phone-statusbar">
 <span id="phone-time"></span>
 <span class="phone-statusbar-right">
 <span class="phone-signal" aria-label="signal"><i></i><i></i><i></i><i></i></span>
 <span class="phone-wifi" aria-label="wifi"><i></i></span>
 <span id="phone-battery" class="phone-battery"></span>
 </span>
 </div>
 <div class="phone-header">
 <button id="phone-back-btn" class="hidden phone-nav-btn" onclick="Phone.goBack()">${_uiIcon('back', 18)}</button>
 <span id="phone-title">手机</span>
 <div id="phone-header-right" style="margin-left:auto;display:flex;align-items:center;gap:4px"></div>
 </div>
 <div id="phone-body" class="phone-body"></div>
 </div>
 `;
    // 不做点击外部关闭（移动端键盘收起会误触）—— 用 ✕ 按钮关闭
    // 阻止滑动手势穿透到底层（底层页面的侧栏/滚动会被误触发）
    modal.addEventListener('touchmove', (e) => {
      // 只允许 phone-shell 内部的可滚动容器滚动，其余位置禁止滑动冒泡
      const target = e.target;
      const shell = modal.querySelector('.phone-shell');
      if (!shell || !shell.contains(target)) {
        e.preventDefault();
        return;
      }
      // 内部元素：允许它自己滚，但不让事件冒到底层
      e.stopPropagation();
    }, { passive: false });
    modal.addEventListener('wheel', (e) => { e.stopPropagation(); }, { passive: true });
    document.body.appendChild(modal);
  }

