  // ===== 世界观自定义直播品类（phoneApps.video.liveCats）同步缓存 =====
  // 结构：{ hiddenPresets:[预设品类名], categories:[{name, desc, plays:['call'|'pk'|'cart']}] }
  // 预设品类靠 name 隐藏（直播预设没有 id）；自建品类只填 name+desc+plays，进间走通用文风兜底。
  // 生成/校验链路同步读取，进直播 App 时异步刷新一次，之后同步用。
  let _liveCustomCfgCache = null;
  const _LIVE_PLAY_IDS = ['call', 'pk', 'cart']; // 三个可勾选玩法：连麦连线 / 礼物PK / 购物车带货
  function _liveNormalizeCustomCfg(raw) {
    const r = (raw && typeof raw === 'object') ? raw : {};
    const cats = Array.isArray(r.categories) ? r.categories : [];
    return {
      hiddenPresets: Array.isArray(r.hiddenPresets) ? r.hiddenPresets.filter(x => typeof x === 'string' && x.trim()) : [],
      categories: cats.filter(c => c && typeof c === 'object' && String(c.name || '').trim()).map(c => ({
        name: String(c.name || '').trim(),
        desc: String(c.desc || '').trim(),
        isCustom: true,
        plays: Array.isArray(c.plays) ? c.plays.filter(x => _LIVE_PLAY_IDS.includes(x)) : [],
      })),
    };
  }
  async function _liveRefreshCustomCfg() {
    try {
      const wv = (typeof Worldview !== 'undefined' && Worldview.getCurrent) ? await Worldview.getCurrent() : null;
      const raw = wv && wv.phoneApps && wv.phoneApps.video ? wv.phoneApps.video.liveCats : null;
      _liveCustomCfgCache = _liveNormalizeCustomCfg(raw);
    } catch (_) {
      _liveCustomCfgCache = _liveNormalizeCustomCfg(null);
    }
    return _liveCustomCfgCache;
  }
  function _liveCustomCfg() {
    return _liveCustomCfgCache || _liveNormalizeCustomCfg(null);
  }
  // 取「最终生效的品类列表」：预设（去掉被隐藏的）+ 自建品类。元素 {name, desc, plays, isCustom}
  function _liveEffectiveTags() {
    const cfg = _liveCustomCfg();
    const hidden = new Set(cfg.hiddenPresets || []);
    const presets = _LIVE_TAGS.filter(t => !hidden.has(t.name)).map(t => ({ name: t.name, desc: t.desc, plays: null, isCustom: false }));
    const customs = (cfg.categories || []).map(c => ({ name: c.name, desc: c.desc, plays: c.plays || [], isCustom: true }));
    return presets.concat(customs);
  }
  // 查某个自建品类是否勾选了某玩法（预设品类返回 false，预设走各自的硬白名单）
  function _liveCustomTagHasPlay(tagName, playId) {
    try {
      const cfg = _liveCustomCfg();
      const cat = (cfg.categories || []).find(c => c.name === (tagName || '').trim());
      return !!(cat && Array.isArray(cat.plays) && cat.plays.includes(playId));
    } catch (_) { return false; }
  }

