        // 角色记事本：刷新出新评论也算观测，抽 NPC 行为落库
        try { _npcNoteFromForumPost(post, _getForumName()); } catch(_) {}
        _log(`刷新了${mt}帖子「${post.title}」的评论，追加了 ${added} 条`);
